export type TimelineEffect = {
  fade_in?: number;
  fade_out?: number;
};

export type ParameterType = 'number' | 'select' | 'boolean' | 'color';

export type ParameterOption = {
  label: string;
  value: string;
};

export type ParameterDefinition = {
  name: string;
  label: string;
  description: string;
  type: ParameterType;
  default?: number | string | boolean;
  min?: number;
  max?: number;
  step?: number;
  options?: ParameterOption[];
};

export type ParameterSchema = ParameterDefinition[];

export type TrackKind = 'visual' | 'audio';
export type TrackFit = 'cover' | 'contain' | 'manual';
export type TrackBlendMode =
  | 'normal'
  | 'multiply'
  | 'screen'
  | 'overlay'
  | 'darken'
  | 'lighten'
  | 'soft-light'
  | 'hard-light';
export type ClipType = 'media' | 'hold' | 'text';

export type TrackDefinition = {
  id: string;
  kind: TrackKind;
  label: string;
  scale?: number;
  fit?: TrackFit;
  opacity?: number;
  blendMode?: TrackBlendMode;
};

export type ClipEntrance = {
  type: string;
  duration: number;
  params?: Record<string, unknown>;
};

export type ClipExit = {
  type: string;
  duration: number;
  params?: Record<string, unknown>;
};

export type ClipContinuous = {
  type: string;
  intensity?: number;
  params?: Record<string, unknown>;
};

export type ClipTransition = {
  type: string;
  duration: number;
};

export type TextAlignment = 'left' | 'center' | 'right';

export type TextClipData = {
  content: string;
  fontFamily?: string;
  fontSize?: number;
  color?: string;
  align?: TextAlignment;
  bold?: boolean;
  italic?: boolean;
};

export type TimelineClip = {
  id: string;
  at: number;
  track: string;
  clipType?: ClipType;
  asset?: string;
  from?: number;
  to?: number;
  speed?: number;
  hold?: number;
  volume?: number;
  x?: number;
  y?: number;
  width?: number;
  height?: number;
  cropTop?: number;
  cropBottom?: number;
  cropLeft?: number;
  cropRight?: number;
  opacity?: number;
  text?: TextClipData;
  entrance?: ClipEntrance;
  exit?: ClipExit;
  continuous?: ClipContinuous;
  transition?: ClipTransition;
  effects?: TimelineEffect[] | Record<string, number>;
};

export type TimelineOutput = {
  resolution: string;
  fps: number;
  file: string;
  background?: string | null;
  background_scale?: number | null;
};

export type CustomEffectEntry = {
  code: string;
  category?: 'entrance' | 'exit' | 'continuous';
};

export type TimelineConfig = {
  output: TimelineOutput;
  clips: TimelineClip[];
  tracks?: TrackDefinition[];
  customEffects?: Record<string, CustomEffectEntry>;
};

export type AssetRegistryEntry = {
  file: string;
  type?: string;
  duration?: number;
  resolution?: string;
  fps?: number;
  generationId?: string;
  variantId?: string;
};

export type AssetRegistry = {
  assets: Record<string, AssetRegistryEntry>;
};

export type ResolvedAssetRegistryEntry = AssetRegistryEntry & {
  src: string;
};

export type ResolvedTimelineClip = TimelineClip & {
  assetEntry?: ResolvedAssetRegistryEntry;
};

export type ResolvedTimelineConfig = {
  output: TimelineOutput;
  tracks: TrackDefinition[];
  clips: ResolvedTimelineClip[];
  registry: Record<string, ResolvedAssetRegistryEntry>;
};

import type {
  AssetRegistry,
  ResolvedAssetRegistryEntry,
  ResolvedTimelineConfig,
  TimelineClip,
  TimelineConfig,
} from '@/tools/video-editor/types';

export const parseResolution = (resolution: string): { width: number; height: number } => {
  const [width, height] = resolution.toLowerCase().split('x');
  return {
    width: Number(width),
    height: Number(height),
  };
};

export const getClipSourceDuration = (clip: TimelineClip): number => {
  if (typeof clip.hold === 'number') {
    return clip.hold;
  }

  return (clip.to ?? 0) - (clip.from ?? 0);
};

export const getClipTimelineDuration = (clip: TimelineClip): number => {
  const speed = clip.speed ?? 1;
  return getClipSourceDuration(clip) / speed;
};

export const secondsToFrames = (seconds: number, fps: number): number => {
  return Math.round(seconds * fps);
};

export const getClipDurationInFrames = (clip: TimelineClip, fps: number): number => {
  return Math.max(1, secondsToFrames(getClipTimelineDuration(clip), fps));
};

export const getTimelineDurationInFrames = (config: ResolvedTimelineConfig, fps: number): number => {
  return Math.max(
    1,
    ...config.clips.map((clip) => {
      return secondsToFrames(clip.at, fps) + getClipDurationInFrames(clip, fps);
    }),
  );
};

export const getEffectValue = (
  effects: TimelineClip['effects'],
  name: 'fade_in' | 'fade_out',
): number | null => {
  if (!effects) {
    return null;
  }

  if (!Array.isArray(effects)) {
    return typeof effects[name] === 'number' ? effects[name] : null;
  }

  for (const effect of effects) {
    if (typeof effect[name] === 'number') {
      return effect[name] ?? null;
    }
  }

  return null;
};

export const getConfigSignature = (
  config: ResolvedTimelineConfig | TimelineConfig,
): string => JSON.stringify(config);

export type UrlResolver = (file: string) => string | Promise<string>;

export const isRemoteUrl = (url: string): boolean => /^https?:\/\//.test(url);

export const resolveTimelineConfig = async (
  config: TimelineConfig,
  registry: AssetRegistry,
  resolveUrl: UrlResolver,
): Promise<ResolvedTimelineConfig> => {
  const resolvedRegistry: Record<string, ResolvedAssetRegistryEntry> = {};

  await Promise.all(
    Object.entries(registry.assets ?? {}).map(async ([assetId, entry]) => {
      resolvedRegistry[assetId] = {
        ...entry,
        src: isRemoteUrl(entry.file) ? entry.file : await resolveUrl(entry.file),
      };
    }),
  );

  const clips = config.clips.map((clip) => {
    if (!clip.asset) {
      return {
        ...clip,
        assetEntry: undefined,
      };
    }

    const assetEntry = resolvedRegistry[clip.asset];
    if (!assetEntry) {
      console.warn(`Clip '${clip.id}' references missing asset '${clip.asset}' - skipping`);
      return {
        ...clip,
        assetEntry: undefined,
      };
    }

    return {
      ...clip,
      assetEntry,
    };
  });

  return {
    output: { ...config.output },
    tracks: config.tracks ?? [],
    clips,
    registry: resolvedRegistry,
  };
};

import React, { useCallback, useEffect, useRef, useState } from 'react';
import { createPortal } from 'react-dom';
import { ImageIcon, Music2, Scissors, Trash2, Type } from 'lucide-react';
import { cn } from '@/shared/components/ui/contracts/cn';
import type { ClipMeta } from '@/tools/video-editor/lib/timeline-data';
import type { TimelineAction } from '@/tools/video-editor/types/timeline-canvas';

interface ContextMenuState {
  x: number;
  y: number;
  clientX: number;
}

interface ClipActionProps {
  action: TimelineAction;
  clipMeta: ClipMeta;
  isSelected: boolean;
  isPrimary?: boolean;
  selectedClipIds?: string[];
  thumbnailSrc?: string;
  onSelect: (clipId: string, trackId: string) => void;
  onDoubleClickAsset?: (assetKey: string) => void;
  onSplitHere?: (clipId: string, clientX: number) => void;
  onSplitClipsAtPlayhead?: (clipIds: string[]) => void;
  onDeleteClip?: (clipId: string) => void;
  onDeleteClips?: (clipIds: string[]) => void;
  onToggleMuteClips?: (clipIds: string[]) => void;
}

export function ClipAction({
  action,
  clipMeta,
  isSelected,
  isPrimary = false,
  selectedClipIds = [],
  thumbnailSrc,
  onSelect,
  onDoubleClickAsset,
  onSplitHere,
  onSplitClipsAtPlayhead,
  onDeleteClip,
  onDeleteClips,
  onToggleMuteClips,
}: ClipActionProps) {
  const [contextMenu, setContextMenu] = useState<ContextMenuState | null>(null);
  const menuRef = useRef<HTMLDivElement>(null);

  const closeMenu = useCallback(() => setContextMenu(null), []);

  useEffect(() => {
    if (!contextMenu) return;
    const handleClickOutside = (e: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(e.target as Node)) {
        closeMenu();
      }
    };
    const handleEscape = (e: KeyboardEvent) => {
      if (e.key === 'Escape') closeMenu();
    };
    document.addEventListener('mousedown', handleClickOutside);
    document.addEventListener('keydown', handleEscape);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
      document.removeEventListener('keydown', handleEscape);
    };
  }, [contextMenu, closeMenu]);

  const handleContextMenu = useCallback((e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (!isSelected) {
      onSelect(action.id, clipMeta.track);
    }
    setContextMenu({ x: e.clientX, y: e.clientY, clientX: e.clientX });
  }, [action.id, clipMeta.track, isSelected, onSelect]);
  const icon = clipMeta.clipType === 'text'
    ? <Type className="h-3 w-3" />
    : clipMeta.track.startsWith('A')
      ? <Music2 className="h-3 w-3" />
      : <ImageIcon className="h-3 w-3" />;
  const hasBatchSelection = isSelected && selectedClipIds.length > 1;
  const effectBadges = [
    clipMeta.entrance?.type ? `In:${clipMeta.entrance.type}` : null,
    clipMeta.continuous?.type ? `Loop:${clipMeta.continuous.type}` : null,
    clipMeta.exit?.type ? `Out:${clipMeta.exit.type}` : null,
  ].filter(Boolean);

  return (
    <>
      <button
        type="button"
        className={cn(
          'clip-action group relative flex h-full w-full overflow-hidden rounded-md border text-left',
          isSelected
            ? 'border-sky-400 bg-sky-500/20 text-sky-50'
            : 'border-border bg-card/90 text-foreground hover:border-accent',
        )}
        data-clip-id={action.id}
        data-row-id={clipMeta.track}
        onPointerDown={(event) => event.stopPropagation()}
        onDoubleClick={(event) => {
          event.stopPropagation();
          if (clipMeta.clipType !== 'text' && clipMeta.asset) {
            onDoubleClickAsset?.(clipMeta.asset);
          }
        }}
        onContextMenu={handleContextMenu}
      >
        {thumbnailSrc ? (
          <img
            src={thumbnailSrc}
            alt=""
            className="h-full w-10 shrink-0 object-cover opacity-80"
            draggable={false}
          />
        ) : (
          <div className="flex h-full w-8 shrink-0 items-center justify-center bg-background/60 text-muted-foreground">
            {icon}
          </div>
        )}
        <div className="min-w-0 flex-1 px-2 py-1">
          <div className="truncate text-[11px] font-medium">
            {clipMeta.text?.content || clipMeta.asset || action.id}
          </div>
          {effectBadges.length > 0 && (
            <div className="mt-1 flex gap-1 overflow-hidden">
              {effectBadges.slice(0, 2).map((badge) => (
                <span key={badge} className="truncate rounded bg-background/60 px-1 py-0.5 text-[9px] uppercase tracking-[0.12em] text-muted-foreground">
                  {badge}
                </span>
              ))}
            </div>
          )}
        </div>
      </button>

      {contextMenu && createPortal(
        <div
          ref={menuRef}
          className="fixed z-50 min-w-[10rem] overflow-hidden rounded-md border bg-popover p-1 text-popover-foreground shadow-md animate-in fade-in-0 zoom-in-95"
          style={{ left: contextMenu.x, top: contextMenu.y }}
        >
          {!hasBatchSelection && onSplitHere && (
            <button
              type="button"
              className="relative flex w-full cursor-default select-none items-center gap-2 rounded-sm px-2 py-1.5 text-sm outline-none transition-colors hover:bg-accent hover:text-accent-foreground"
              onClick={() => {
                onSplitHere(action.id, contextMenu.clientX);
                closeMenu();
              }}
            >
              <Scissors className="h-4 w-4" />
              Split Here
            </button>
          )}
          {hasBatchSelection && onToggleMuteClips && (
            <button
              type="button"
              className="relative flex w-full cursor-default select-none items-center gap-2 rounded-sm px-2 py-1.5 text-sm outline-none transition-colors hover:bg-accent hover:text-accent-foreground"
              onClick={() => {
                onToggleMuteClips(selectedClipIds);
                closeMenu();
              }}
            >
              <Music2 className="h-4 w-4" />
              Mute/Unmute {selectedClipIds.length} clips
            </button>
          )}
          {hasBatchSelection && onSplitClipsAtPlayhead && (
            <button
              type="button"
              className="relative flex w-full cursor-default select-none items-center gap-2 rounded-sm px-2 py-1.5 text-sm outline-none transition-colors hover:bg-accent hover:text-accent-foreground"
              onClick={() => {
                onSplitClipsAtPlayhead(selectedClipIds);
                closeMenu();
              }}
            >
              <Scissors className="h-4 w-4" />
              Split {selectedClipIds.length} clips at playhead
            </button>
          )}
          {hasBatchSelection && onDeleteClips ? (
            <button
              type="button"
              className="relative flex w-full cursor-default select-none items-center gap-2 rounded-sm px-2 py-1.5 text-sm outline-none transition-colors hover:bg-destructive hover:text-destructive-foreground"
              onClick={() => {
                onDeleteClips(selectedClipIds);
                closeMenu();
              }}
            >
              <Trash2 className="h-4 w-4" />
              Delete {selectedClipIds.length} clips
              <span className="ml-auto text-xs tracking-widest opacity-60">Del</span>
            </button>
          ) : onDeleteClip && (
            <button
              type="button"
              className="relative flex w-full cursor-default select-none items-center gap-2 rounded-sm px-2 py-1.5 text-sm outline-none transition-colors hover:bg-destructive hover:text-destructive-foreground"
              onClick={() => {
                onDeleteClip(action.id);
                closeMenu();
              }}
            >
              <Trash2 className="h-4 w-4" />
              Delete Clip
              <span className="ml-auto text-xs tracking-widest opacity-60">Del</span>
            </button>
          )}
        </div>,
        document.body,
      )}
    </>
  );
}

import type { CSSProperties, FC, ReactNode } from 'react';
import { AbsoluteFill, Img, Sequence, interpolate, useCurrentFrame, useVideoConfig } from 'remotion';
import { Video } from '@remotion/media';
import { getClipDurationInFrames, parseResolution, secondsToFrames } from '@/tools/video-editor/lib/config-utils';
import { wrapWithClipEffects } from '@/tools/video-editor/effects';
import { transitions } from '@/tools/video-editor/effects/transitions';
import { computeViewportMediaLayout } from '@/tools/video-editor/lib/render-bounds';
import type { ResolvedTimelineClip, TrackDefinition } from '@/tools/video-editor/types';

type VisualClipProps = {
  clip: ResolvedTimelineClip;
  track: TrackDefinition;
  fps: number;
  predecessor?: ResolvedTimelineClip | null;
};

const getClipBoxStyle = (
  clip: ResolvedTimelineClip,
  track: TrackDefinition,
  compositionWidth: number,
  compositionHeight: number,
): CSSProperties => {
  const hasPositionOverride = (
    clip.x !== undefined
    || clip.y !== undefined
    || clip.width !== undefined
    || clip.height !== undefined
    || clip.cropTop !== undefined
    || clip.cropBottom !== undefined
    || clip.cropLeft !== undefined
    || clip.cropRight !== undefined
  );
  const fit = track.fit ?? 'contain';
  const style: CSSProperties = fit === 'manual' || hasPositionOverride
    ? {
        position: 'absolute',
        left: clip.x ?? 0,
        top: clip.y ?? 0,
        width: clip.width ?? compositionWidth,
        height: clip.height ?? compositionHeight,
        objectFit: 'cover',
        opacity: clip.opacity ?? 1,
      }
    : {
        width: '100%',
        height: '100%',
        objectFit: fit,
        opacity: clip.opacity ?? 1,
      };
  const cropTop = clip.cropTop ?? 0;
  const cropRight = clip.cropRight ?? 0;
  const cropBottom = clip.cropBottom ?? 0;
  const cropLeft = clip.cropLeft ?? 0;

  if (cropTop || cropRight || cropBottom || cropLeft) {
    style.clipPath = `inset(${cropTop * 100}% ${cropRight * 100}% ${cropBottom * 100}% ${cropLeft * 100}%)`;
  }

  return style;
};

const getIntrinsicMediaSize = (
  clip: ResolvedTimelineClip,
  compositionWidth: number,
  compositionHeight: number,
): { width: number; height: number } => {
  const resolution = clip.assetEntry?.resolution;
  if (resolution) {
    const parsed = parseResolution(resolution);
    if (Number.isFinite(parsed.width) && Number.isFinite(parsed.height) && parsed.width > 0 && parsed.height > 0) {
      return parsed;
    }
  }

  return {
    width: clip.width ?? compositionWidth,
    height: clip.height ?? compositionHeight,
  };
};

const VisualAsset: FC<VisualClipProps> = ({ clip, track, fps }) => {
  const { width: compositionWidth, height: compositionHeight } = useVideoConfig();

  if (!clip.assetEntry) {
    return null;
  }

  const clipVolume = clip.volume ?? 1;
  const isImage = clip.assetEntry.type?.startsWith('image');
  const hasPositionOverride = (
    clip.x !== undefined
    || clip.y !== undefined
    || clip.width !== undefined
    || clip.height !== undefined
    || clip.cropTop !== undefined
    || clip.cropBottom !== undefined
    || clip.cropLeft !== undefined
    || clip.cropRight !== undefined
  );
  const fit = track.fit ?? 'contain';
  const useViewportLayout = fit === 'manual' || hasPositionOverride;

  if (!useViewportLayout) {
    const style = getClipBoxStyle(clip, track, compositionWidth, compositionHeight);
    const sharedStyle: CSSProperties = {
      ...style,
      mixBlendMode: track.blendMode && track.blendMode !== 'normal' ? track.blendMode : undefined,
    };

    if (isImage) {
      return <Img src={clip.assetEntry.src} style={sharedStyle} crossOrigin="anonymous" />;
    }

    return (
      <Video
        src={clip.assetEntry.src}
        startFrom={secondsToFrames(clip.from ?? 0, fps)}
        playbackRate={clip.speed ?? 1}
        volume={clipVolume}
        muted={clipVolume <= 0}
        style={sharedStyle}
        crossOrigin="anonymous"
      />
    );
  }

  const fullBounds = {
    x: clip.x ?? 0,
    y: clip.y ?? 0,
    width: clip.width ?? compositionWidth,
    height: clip.height ?? compositionHeight,
  };
  const intrinsicSize = getIntrinsicMediaSize(clip, compositionWidth, compositionHeight);
  const viewportLayout = computeViewportMediaLayout({
    fullBounds,
    cropValues: {
      cropTop: clip.cropTop,
      cropBottom: clip.cropBottom,
      cropLeft: clip.cropLeft,
      cropRight: clip.cropRight,
    },
    compositionWidth,
    compositionHeight,
    intrinsicWidth: intrinsicSize.width,
    intrinsicHeight: intrinsicSize.height,
  });

  if (!viewportLayout) {
    return null;
  }

  const viewportStyle: CSSProperties = {
    position: 'absolute',
    left: viewportLayout.renderBounds.x,
    top: viewportLayout.renderBounds.y,
    width: viewportLayout.renderBounds.width,
    height: viewportLayout.renderBounds.height,
    overflow: 'hidden',
    opacity: clip.opacity ?? 1,
  };
  const mediaStyle: CSSProperties = {
    position: 'absolute',
    left: viewportLayout.mediaBounds.x,
    top: viewportLayout.mediaBounds.y,
    width: viewportLayout.mediaBounds.width,
    height: viewportLayout.mediaBounds.height,
    // Override Tailwind preflight's `img { max-width: 100%; height: auto; }`
    // which would squash the media to fit the viewport container. The media
    // must overflow the container (clipped by overflow:hidden) for the
    // manual cover layout to work correctly.
    maxWidth: 'none',
    maxHeight: 'none',
    mixBlendMode: track.blendMode && track.blendMode !== 'normal' ? track.blendMode : undefined,
  };

  if (isImage) {
    return (
      <div style={viewportStyle}>
        <Img src={clip.assetEntry.src} style={mediaStyle} crossOrigin="anonymous" />
      </div>
    );
  }

  return (
    <div style={viewportStyle}>
      <Video
        src={clip.assetEntry.src}
        startFrom={secondsToFrames(clip.from ?? 0, fps)}
        playbackRate={clip.speed ?? 1}
        volume={clipVolume}
        muted={clipVolume <= 0}
        style={mediaStyle}
        crossOrigin="anonymous"
      />
    </div>
  );
};

export const VisualClip: FC<VisualClipProps> = ({ clip, track, fps }) => {
  const durationInFrames = getClipDurationInFrames(clip, fps);
  const frame = useCurrentFrame();
  const transitionRenderer = clip.transition ? transitions[clip.transition.type] : undefined;
  const transitionProgress = interpolate(
    frame,
    [0, Math.max(1, secondsToFrames(clip.transition?.duration ?? 0.4, fps))],
    [0, 1],
    {
      extrapolateLeft: 'clamp',
      extrapolateRight: 'clamp',
    },
  );
  const transitionStyle = transitionRenderer ? transitionRenderer(transitionProgress) : undefined;

  const content: ReactNode = (
    <AbsoluteFill style={{ overflow: 'hidden', ...transitionStyle }}>
      <VisualAsset clip={clip} track={track} fps={fps} />
    </AbsoluteFill>
  );

  return <>{wrapWithClipEffects(content, clip, durationInFrames, fps)}</>;
};

const LazyGuard: FC<{ durationInFrames: number; children: ReactNode }> = ({ durationInFrames, children }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();
  const bufferFrames = Math.max(1, Math.round(fps));

  if (frame < -bufferFrames || frame > durationInFrames + bufferFrames) {
    return null;
  }

  return <>{children}</>;
};

export const VisualClipSequence: FC<VisualClipProps> = ({ clip, track, fps, predecessor }) => {
  const durationInFrames = getClipDurationInFrames(clip, fps);
  const transitionFrames = predecessor && clip.transition
    ? secondsToFrames(clip.transition.duration, fps)
    : 0;
  const from = Math.max(0, secondsToFrames(clip.at, fps) - transitionFrames);

  return (
    <Sequence key={clip.id} from={from} durationInFrames={durationInFrames}>
      <LazyGuard durationInFrames={durationInFrames}>
        <VisualClip clip={clip} track={track} fps={fps} predecessor={predecessor} />
      </LazyGuard>
    </Sequence>
  );
};

import type {
  TimelineAction,
  TimelineEffect as EditorTimelineEffect,
  TimelineRow,
} from '@/tools/video-editor/types/timeline-canvas';
import {
  getClipSourceDuration,
  getConfigSignature,
  resolveTimelineConfig as resolveTimelineConfigShared,
  type UrlResolver,
} from '@/tools/video-editor/lib/config-utils';
import { migrateToFlatTracks, repairConfig } from '@/tools/video-editor/lib/migrate';
import { TIMELINE_CLIP_FIELDS, validateSerializedConfig } from '@/tools/video-editor/lib/serialize';
import type { DataProvider } from '@/tools/video-editor/data/DataProvider';
import type {
  AssetRegistry,
  ClipType,
  ResolvedTimelineConfig,
  TimelineClip,
  TimelineConfig,
  TimelineOutput,
  TrackDefinition,
  TrackKind,
} from '@/tools/video-editor/types';

export interface ClipMeta {
  asset?: string;
  track: string;
  clipType?: ClipType;
  from?: number;
  to?: number;
  speed?: number;
  hold?: number;
  volume?: number;
  x?: number;
  y?: number;
  width?: number;
  height?: number;
  cropTop?: number;
  cropBottom?: number;
  cropLeft?: number;
  cropRight?: number;
  opacity?: number;
  text?: TimelineClip['text'];
  entrance?: TimelineClip['entrance'];
  exit?: TimelineClip['exit'];
  continuous?: TimelineClip['continuous'];
  transition?: TimelineClip['transition'];
  effects?: TimelineClip['effects'];
}

export interface TranscriptSegment {
  start: number;
  end: number;
  text: string;
}

export type ClipOrderMap = Record<string, string[]>;

export interface TimelineData {
  config: TimelineConfig;
  configVersion: number;
  registry: AssetRegistry;
  resolvedConfig: ResolvedTimelineConfig;
  rows: TimelineRow[];
  meta: Record<string, ClipMeta>;
  effects: Record<string, EditorTimelineEffect>;
  assetMap: Record<string, string>;
  output: TimelineOutput;
  tracks: TrackDefinition[];
  clipOrder: ClipOrderMap;
  signature: string;
}

const ASSET_COLORS: Record<string, string> = {
  'output-composition': '#e06c75',
  'venn-diagram': '#61afef',
  'demo-one': '#98c379',
  'demo-two': '#c678dd',
  'example-video': '#56b6c2',
  'example-image1': '#d19a66',
  'example-image2': '#e5c07b',
  input: '#61afef',
};

const round = (value: number): number => Math.round(value * 100) / 100;

const effectIdForClip = (clipId: string): string => `effect-${clipId}`;


const getClipDurationSeconds = (clip: TimelineClip): number => {
  return getClipSourceDuration(clip) / (clip.speed ?? 1);
};

const getDefaultClipMeta = (clip: TimelineClip): ClipMeta => {
  return {
    asset: clip.asset,
    track: clip.track,
    clipType: clip.clipType,
    from: clip.from,
    to: clip.to,
    speed: clip.speed,
    hold: clip.hold,
    volume: clip.volume,
    x: clip.x,
    y: clip.y,
    width: clip.width,
    height: clip.height,
    cropTop: clip.cropTop,
    cropBottom: clip.cropBottom,
    cropLeft: clip.cropLeft,
    cropRight: clip.cropRight,
    opacity: clip.opacity,
    text: clip.text,
    entrance: clip.entrance,
    exit: clip.exit,
    continuous: clip.continuous,
    transition: clip.transition,
    effects: clip.effects,
  };
};

const resolveAssetUrl = (file: string): string => {
  if (/^https?:\/\//.test(file)) {
    return file;
  }

  const normalized = file.replace(/\\/g, '/').replace(/^\/+/, '');
  return `/${normalized}`;
};

const buildAssetMap = (registry: AssetRegistry): Record<string, string> => {
  return Object.fromEntries(
    Object.entries(registry.assets ?? {}).map(([assetId, entry]) => [assetId, entry.file]),
  );
};

export const resolveTimelineConfig = async (
  config: TimelineConfig,
  registry: AssetRegistry,
  urlResolver?: UrlResolver,
): Promise<ResolvedTimelineConfig> => {
  return resolveTimelineConfigShared(config, registry, urlResolver ?? resolveAssetUrl);
};

export const configToRows = (
  config: TimelineConfig,
): Pick<TimelineData, 'rows' | 'meta' | 'effects' | 'clipOrder' | 'tracks'> => {
  const clipOrder: ClipOrderMap = Object.fromEntries(
    (config.tracks ?? []).map((track) => [track.id, []]),
  );
  const effects: Record<string, EditorTimelineEffect> = {};
  const meta: Record<string, ClipMeta> = {};
  const rowsByTrack = new Map<string, TimelineAction[]>();

  for (const track of config.tracks ?? []) {
    rowsByTrack.set(track.id, []);
  }

  for (const clip of config.clips) {
    const clipId = clip.id;

    clipOrder[clip.track] ??= [];
    clipOrder[clip.track].push(clipId);
    effects[effectIdForClip(clipId)] = { id: effectIdForClip(clipId) };
    meta[clipId] = getDefaultClipMeta(clip);

    const action: TimelineAction = {
      id: clipId,
      start: clip.at,
      end: clip.at + getClipDurationSeconds(clip),
      effectId: effectIdForClip(clipId),
    };

    rowsByTrack.get(clip.track)?.push(action);
  }

  return {
    rows: (config.tracks ?? []).map((track) => ({
      id: track.id,
      actions: rowsByTrack.get(track.id) ?? [],
    })),
    meta,
    effects,
    clipOrder,
    tracks: config.tracks ?? [],
  };
};

export const rowsToConfig = (
  rows: TimelineRow[],
  meta: Record<string, ClipMeta>,
  output: TimelineOutput,
  clipOrder: ClipOrderMap,
  tracks: TrackDefinition[],
  customEffects?: TimelineConfig['customEffects'],
): TimelineConfig => {
  const actionMap = new Map<string, TimelineAction>();
  const trackActionIds: Record<string, string[]> = Object.fromEntries(tracks.map((track) => [track.id, []]));

  for (const row of rows) {
    for (const action of row.actions) {
      if (action.id.startsWith('uploading-')) continue;
      const clipMeta = meta[action.id];
      if (!clipMeta) {
        continue;
      }

      actionMap.set(action.id, action);
      trackActionIds[row.id] ??= [];
      trackActionIds[row.id].push(action.id);
    }
  }

  const clips: TimelineClip[] = [];
  for (const track of tracks) {
    const baseOrder = (clipOrder[track.id] ?? []).filter((clipId) => actionMap.has(clipId));
    const appendedIds = (trackActionIds[track.id] ?? []).filter((clipId) => !baseOrder.includes(clipId));

    for (const clipId of [...baseOrder, ...appendedIds]) {
      const action = actionMap.get(clipId);
      const clipMeta = meta[clipId];
      if (!action || !clipMeta) {
        continue;
      }

      const nextClip: Partial<TimelineClip> = {
        id: clipId,
        at: round(action.start),
        track: track.id,
        clipType: clipMeta.clipType,
        asset: clipMeta.asset,
        from: clipMeta.from,
        to: clipMeta.to,
        speed: clipMeta.speed,
        hold: clipMeta.hold,
        volume: clipMeta.volume,
        x: clipMeta.x,
        y: clipMeta.y,
        width: clipMeta.width,
        height: clipMeta.height,
        cropTop: clipMeta.cropTop,
        cropBottom: clipMeta.cropBottom,
        cropLeft: clipMeta.cropLeft,
        cropRight: clipMeta.cropRight,
        opacity: clipMeta.opacity,
        text: clipMeta.text,
        entrance: clipMeta.entrance,
        exit: clipMeta.exit,
        continuous: clipMeta.continuous,
        transition: clipMeta.transition,
        effects: clipMeta.effects,
      };

      if (typeof clipMeta.hold === 'number') {
        nextClip.hold = round(action.end - action.start);
        delete nextClip.from;
        delete nextClip.to;
        delete nextClip.speed;
      } else {
        const speed = clipMeta.speed ?? 1;
        const from = clipMeta.from ?? 0;
        nextClip.from = round(from);
        nextClip.to = round(getSourceTime({ from, start: action.start, speed }, action.end));
      }

      const serializedClip: Partial<TimelineClip> = {
        id: nextClip.id,
        at: nextClip.at,
        track: nextClip.track,
      };

      if (nextClip.asset !== undefined) {
        serializedClip.asset = nextClip.asset;
      }

      for (const field of TIMELINE_CLIP_FIELDS) {
        if (field in serializedClip) {
          continue;
        }

        const value = nextClip[field];
        if (value !== undefined) {
          serializedClip[field] = value as never;
        }
      }

      clips.push(serializedClip as TimelineClip);
    }
  }

  const config: TimelineConfig = {
    output: { ...output },
    tracks: tracks.map((track) => ({ ...track })),
    clips,
  };
  if (customEffects && Object.keys(customEffects).length > 0) {
    config.customEffects = customEffects;
  }
  validateSerializedConfig(config);
  return config;
};

const sortTracksByKind = (tracks: TrackDefinition[]): TrackDefinition[] => {
  const visual = tracks.filter((track) => track.kind === 'visual');
  const audio = tracks.filter((track) => track.kind === 'audio');
  return [...visual, ...audio];
};

interface AssembleTimelineDataParams {
  config: TimelineConfig;
  configVersion: number;
  registry: AssetRegistry;
  resolvedConfig: ResolvedTimelineConfig;
  output: TimelineOutput;
  assetMap: Record<string, string>;
}

/**
 * Assembles TimelineData from already-derived inputs.
 * The provided config must already be migrated to the canonical flat-track shape.
 */
export const assembleTimelineData = ({
  config,
  configVersion,
  registry,
  resolvedConfig,
  output,
  assetMap,
}: AssembleTimelineDataParams): TimelineData => {
  const rowData = configToRows(config);

  return {
    config,
    configVersion,
    registry,
    resolvedConfig,
    rows: rowData.rows,
    meta: rowData.meta,
    effects: rowData.effects,
    assetMap,
    output,
    tracks: rowData.tracks,
    clipOrder: rowData.clipOrder,
    signature: getConfigSignature(resolvedConfig),
  };
};

export const buildTimelineData = async (
  config: TimelineConfig,
  registry: AssetRegistry,
  urlResolver?: UrlResolver,
  configVersion = 1,
): Promise<TimelineData> => {
  // Repair first (dedup corrupted data), then migrate (structural transform).
  // repairConfig is a no-op on clean data. This only runs on load from server.
  const repairedConfig = repairConfig(config);
  const migratedConfig = migrateToFlatTracks(repairedConfig);
  migratedConfig.tracks = migratedConfig.tracks ?? [];
  const resolvedConfig = await resolveTimelineConfig(migratedConfig, registry, urlResolver);

  return assembleTimelineData({
    config: migratedConfig,
    configVersion,
    registry,
    resolvedConfig,
    output: { ...migratedConfig.output },
    assetMap: buildAssetMap(registry),
  });
};

export const loadTimelineJsonFromProvider = async (
  provider: DataProvider,
  timelineId: string,
): Promise<TimelineData> => {
  const [loadedTimeline, registry] = await Promise.all([
    provider.loadTimeline(timelineId),
    provider.loadAssetRegistry(timelineId),
  ]);

  return buildTimelineData(
    loadedTimeline.config,
    registry,
    (file) => provider.resolveAssetUrl(file),
    loadedTimeline.configVersion,
  );
};

export async function loadTranscript(
  provider: DataProvider,
  assetKey: string,
): Promise<TranscriptSegment[]> {
  const profile = await provider.loadAssetProfile?.(assetKey);
  return profile?.transcript?.segments ?? [];
}

export function getAssetColor(asset: string): string {
  return ASSET_COLORS[asset] ?? '#abb2bf';
}

export function getSourceTime(clip: { from: number; start: number; speed: number }, time: number): number {
  return clip.from + (time - clip.start) * clip.speed;
}

export function inferTrackType(filePath: string): TrackKind {
  const ext = filePath.slice(filePath.lastIndexOf('.')).toLowerCase();
  if (['.mp4', '.webm', '.mov'].includes(ext)) {
    return 'visual';
  }

  if (['.mp3', '.wav', '.aac', '.m4a'].includes(ext)) {
    return 'audio';
  }

  return 'visual';
}

export function preserveUploadingClips(source: TimelineData, target: TimelineData): TimelineData {
  const uploadingMeta: Record<string, ClipMeta> = {};
  const uploadingActions: Record<string, TimelineAction[]> = {};
  let found = false;
  for (const row of source.rows) {
    for (const action of row.actions) {
      if (action.id.startsWith('uploading-') && source.meta[action.id]) {
        uploadingActions[row.id] ??= [];
        uploadingActions[row.id].push(action);
        uploadingMeta[action.id] = source.meta[action.id];
        found = true;
      }
    }
  }
  if (!found) return target;

  const nextRows = target.rows.map((row) => {
    const extras = uploadingActions[row.id];
    return extras ? { ...row, actions: [...row.actions, ...extras] } : row;
  });
  return { ...target, rows: nextRows, meta: { ...target.meta, ...uploadingMeta } };
}

export function getNextClipId(meta: Record<string, ClipMeta>): string {
  let max = -1;
  for (const id of Object.keys(meta)) {
    const match = id.match(/^clip-(\d+)$/);
    if (match) {
      max = Math.max(max, Number.parseInt(match[1], 10));
    }
  }
  return `clip-${max + 1}`;
}

