import { useMemo } from 'react';
import type { UseMutationOptions, UseMutationResult } from '@tanstack/react-query';
import {
  useCreateResource,
  useDeleteResource,
  useListPublicResources,
  useListResources,
  useUpdateResource,
  type EffectMetadata,
  type Resource,
} from '@/features/resources/hooks/useResources';

export type EffectCategory = EffectMetadata['category'];

export type EffectResource = EffectMetadata & {
  id: string;
  type: 'effect';
  userId?: string;
  user_id?: string;
  isPublic?: boolean;
  is_public?: boolean;
  createdAt?: string;
  created_at?: string;
};

export type EffectResourcesByCategory = Record<EffectCategory, EffectResource[]>;

const EMPTY_EFFECT_GROUPS: EffectResourcesByCategory = {
  entrance: [],
  exit: [],
  continuous: [],
};

function toEffectResource(resource: Resource): EffectResource {
  const metadata = resource.metadata as EffectMetadata;
  return {
    id: resource.id,
    type: 'effect',
    userId: resource.userId,
    user_id: resource.user_id,
    isPublic: resource.isPublic,
    is_public: resource.is_public,
    createdAt: resource.createdAt,
    created_at: resource.created_at,
    ...metadata,
  };
}

function dedupeEffectResources(resources: Resource[]): EffectResource[] {
  const deduped = new Map<string, EffectResource>();

  for (const resource of resources) {
    deduped.set(resource.id, toEffectResource(resource));
  }

  return [...deduped.values()];
}

function groupEffectResources(resources: EffectResource[]): EffectResourcesByCategory {
  return resources.reduce<EffectResourcesByCategory>((groups, resource) => {
    groups[resource.category].push(resource);
    return groups;
  }, {
    entrance: [],
    exit: [],
    continuous: [],
  });
}

export function useEffectResources(userId: string | null | undefined) {
  const privateEffectsQuery = useListResources('effect');
  const publicEffectsQuery = useListPublicResources('effect');

  const effects = useMemo(() => {
    const privateResources = userId ? privateEffectsQuery.data ?? [] : [];
    const publicResources = publicEffectsQuery.data ?? [];
    return dedupeEffectResources([...privateResources, ...publicResources]);
  }, [privateEffectsQuery.data, publicEffectsQuery.data, userId]);

  const byCategory = useMemo(() => {
    if (effects.length === 0) {
      return EMPTY_EFFECT_GROUPS;
    }

    return groupEffectResources(effects);
  }, [effects]);

  return {
    data: byCategory,
    effects,
    entrance: byCategory.entrance,
    exit: byCategory.exit,
    continuous: byCategory.continuous,
    isLoading: privateEffectsQuery.isLoading || publicEffectsQuery.isLoading,
    isFetching: privateEffectsQuery.isFetching || publicEffectsQuery.isFetching,
    error: privateEffectsQuery.error ?? publicEffectsQuery.error ?? null,
    refetch: async () => {
      const results = await Promise.all([privateEffectsQuery.refetch(), publicEffectsQuery.refetch()]);
      return results;
    },
    privateEffectsQuery,
    publicEffectsQuery,
  };
}

export function useCreateEffectResource(): Omit<
  UseMutationResult<Resource, Error, { metadata: EffectMetadata }, unknown>,
  'mutate' | 'mutateAsync'
> & {
  mutate: UseMutationResult<Resource, Error, { metadata: EffectMetadata }, unknown>['mutate'];
  mutateAsync: (variables: { metadata: EffectMetadata }, options?: UseMutationOptions<Resource, Error, { metadata: EffectMetadata }, unknown>) => Promise<Resource>;
} {
  const mutation = useCreateResource();

  return {
    ...mutation,
    mutate: (variables, options) => mutation.mutate({ type: 'effect', metadata: variables.metadata }, options),
    mutateAsync: (variables, options) => mutation.mutateAsync({ type: 'effect', metadata: variables.metadata }, options),
  };
}

export function useUpdateEffectResource(): Omit<
  UseMutationResult<Resource, Error, { id: string; metadata: EffectMetadata }, unknown>,
  'mutate' | 'mutateAsync'
> & {
  mutate: UseMutationResult<Resource, Error, { id: string; metadata: EffectMetadata }, unknown>['mutate'];
  mutateAsync: (variables: { id: string; metadata: EffectMetadata }, options?: UseMutationOptions<Resource, Error, { id: string; metadata: EffectMetadata }, unknown>) => Promise<Resource>;
} {
  const mutation = useUpdateResource();

  return {
    ...mutation,
    mutate: (variables, options) => mutation.mutate({ id: variables.id, type: 'effect', metadata: variables.metadata }, options),
    mutateAsync: (variables, options) => mutation.mutateAsync({ id: variables.id, type: 'effect', metadata: variables.metadata }, options),
  };
}

export function useDeleteEffectResource(): Omit<
  UseMutationResult<void, Error, { id: string }, unknown>,
  'mutate' | 'mutateAsync'
> & {
  mutate: UseMutationResult<void, Error, { id: string }, unknown>['mutate'];
  mutateAsync: (variables: { id: string }, options?: UseMutationOptions<void, Error, { id: string }, unknown>) => Promise<void>;
} {
  const mutation = useDeleteResource();

  return {
    ...mutation,
    mutate: (variables, options) => mutation.mutate({ id: variables.id, type: 'effect' }, options),
    mutateAsync: (variables, options) => mutation.mutateAsync({ id: variables.id, type: 'effect' }, options),
  };
}

import type { FC } from 'react';
import type { EffectComponentProps } from '@/tools/video-editor/effects/entrances';
import { compileEffect, compileEffectAsync } from '@/tools/video-editor/effects/compileEffect';

export class DynamicEffectRegistry {
  private builtIn: Record<string, FC<EffectComponentProps>>;
  private dynamic: Record<string, { component: FC<EffectComponentProps>; code: string }> = {};

  constructor(builtIn: Record<string, FC<EffectComponentProps>>) {
    this.builtIn = { ...builtIn };
  }

  register(name: string, code: string): void {
    const component = compileEffect(code);
    this.dynamic[this.normalizeName(name)] = { component, code };
  }

  async registerAsync(name: string, code: string): Promise<void> {
    const component = await compileEffectAsync(code);
    this.dynamic[this.normalizeName(name)] = { component, code };
  }

  unregister(name: string): void {
    delete this.dynamic[this.normalizeName(name)];
  }

  get(name: string): FC<EffectComponentProps> | undefined {
    const normalized = this.normalizeName(name);
    return this.builtIn[normalized] ?? this.dynamic[normalized]?.component;
  }

  getCode(name: string): string | undefined {
    return this.dynamic[this.normalizeName(name)]?.code;
  }

  listAll(): string[] {
    return [...new Set([...Object.keys(this.builtIn), ...Object.keys(this.dynamic)])];
  }

  isDynamic(name: string): boolean {
    const normalized = this.normalizeName(name);
    return normalized in this.dynamic && !(normalized in this.builtIn);
  }

  getAllDynamicCode(): Record<string, string> {
    return Object.fromEntries(
      Object.entries(this.dynamic).map(([name, { code }]) => [name, code]),
    );
  }

  private normalizeName(name: string): string {
    return name.startsWith('custom:') ? name.slice(7) : name;
  }
}

import React, { type FC } from 'react';
import { AbsoluteFill, interpolate, spring, useCurrentFrame, useVideoConfig } from 'remotion';
import type { EffectComponentProps } from '@/tools/video-editor/effects/entrances';

let transformSync: typeof import('sucrase').transform | null = null;

export type CompileResult =
  | { ok: true; component: FC<EffectComponentProps> }
  | { ok: false; error: string };

async function getTransform() {
  if (!transformSync) {
    const sucrase = await import('sucrase');
    transformSync = sucrase.transform;
  }

  return transformSync;
}

const CompileErrorEffect: FC<EffectComponentProps & { error: string }> = ({ children, error }) => {
  return (
    <AbsoluteFill style={{ width: '100%', height: '100%' }}>
      {children}
      <AbsoluteFill
        style={{
          background: 'rgba(120, 0, 0, 0.85)',
          color: '#fff',
          fontFamily: 'monospace',
          fontSize: 20,
          padding: 24,
          whiteSpace: 'pre-wrap',
          overflow: 'hidden',
        }}
      >
        {error}
      </AbsoluteFill>
    </AbsoluteFill>
  );
};

function createFailedEffect(message: string): FC<EffectComponentProps> {
  return function FailedEffect(props: EffectComponentProps) {
    return <CompileErrorEffect {...props} error={`Custom effect compilation failed:\n${message}`} />;
  };
}

function tryCompileWithTransform(
  code: string,
  transform: typeof import('sucrase').transform,
): CompileResult {
  try {
    const result = transform(code, {
      transforms: ['jsx', 'typescript'],
      jsxRuntime: 'classic',
      production: true,
    });

    const wrappedCode = `
      var exports = {};
      var module = { exports: exports };
      ${result.code}
      return exports.default || module.exports.default || module.exports;
    `;

    const factory = new Function(
      'React',
      'useCurrentFrame',
      'useVideoConfig',
      'interpolate',
      'spring',
      'AbsoluteFill',
      wrappedCode,
    ) as (...args: unknown[]) => unknown;

    const component = factory(React, useCurrentFrame, useVideoConfig, interpolate, spring, AbsoluteFill);

    if (typeof component !== 'function') {
      throw new Error('Effect code did not produce a valid component (expected a function as default export)');
    }

    return {
      ok: true,
      component: component as FC<EffectComponentProps>,
    };
  } catch (error) {
    return {
      ok: false,
      error: error instanceof Error ? error.message : String(error),
    };
  }
}

function compileWithTransform(
  code: string,
  transform: typeof import('sucrase').transform,
): FC<EffectComponentProps> {
  const result = tryCompileWithTransform(code, transform);
  return result.ok ? result.component : createFailedEffect(result.error);
}

export async function preloadSucrase(): Promise<void> {
  await getTransform();
}

export function compileEffect(code: string): FC<EffectComponentProps> {
  if (!transformSync) {
    return createFailedEffect('Sucrase is not loaded yet.');
  }

  return compileWithTransform(code, transformSync);
}

export async function tryCompileEffectAsync(code: string): Promise<CompileResult> {
  return tryCompileWithTransform(code, await getTransform());
}

export async function compileEffectAsync(code: string): Promise<FC<EffectComponentProps>> {
  const result = await tryCompileEffectAsync(code);
  return result.ok ? result.component : createFailedEffect(result.error);
}

