import { useCallback, useEffect, useMemo, useRef } from 'react';
import type { MutableRefObject } from 'react';
import type {
  DropIndicatorHandle,
  DropIndicatorPosition,
} from '@/tools/video-editor/components/TimelineEditor/DropIndicator';
import {
  computeDropPosition,
  type DropPosition,
} from '@/tools/video-editor/lib/drop-position';
import type { GhostRect } from '@/tools/video-editor/lib/multi-drag-utils';
import type { TimelineData } from '@/tools/video-editor/lib/timeline-data';
import type { TrackKind } from '@/tools/video-editor/types';

export interface DragCoordinator {
  update(params: {
    clientX: number;
    clientY: number;
    sourceKind: TrackKind | null;
    clipDuration?: number;
    clipOffsetX?: number;
  }): DropPosition;
  /** Show ghost outlines for secondary clips (non-anchor) during multi-drag. */
  showSecondaryGhosts(ghosts: GhostRect[]): void;
  end(): void;
  lastPosition: DropPosition | null;
  editAreaRef: MutableRefObject<HTMLElement | null>;
}

interface UseDragCoordinatorArgs {
  dataRef: MutableRefObject<TimelineData | null>;
  scale: number;
  scaleWidth: number;
  startLeft: number;
  rowHeight: number;
}

interface UseDragCoordinatorResult {
  coordinator: DragCoordinator;
  indicatorRef: MutableRefObject<DropIndicatorHandle | null>;
  editAreaRef: MutableRefObject<HTMLElement | null>;
}

const buildFallbackPosition = (rowHeight: number, sourceKind: TrackKind | null): DropPosition => ({
  time: 0,
  rowIndex: 0,
  trackId: undefined,
  trackKind: sourceKind,
  trackName: '',
  isNewTrack: false,
  isReject: false,
  newTrackKind: null,
  screenCoords: {
    rowTop: 0,
    rowLeft: 0,
    rowWidth: 0,
    rowHeight,
    clipLeft: 0,
    clipWidth: 0,
    ghostCenter: 0,
  },
});

const toIndicatorPosition = (position: DropPosition): DropIndicatorPosition => {
  const timeLabel = `${position.time.toFixed(1)}s`;
  return {
    rowTop: position.screenCoords.rowTop,
    rowHeight: position.screenCoords.rowHeight,
    rowLeft: position.screenCoords.rowLeft,
    rowWidth: position.screenCoords.rowWidth,
    lineLeft: position.screenCoords.ghostCenter,
    ghostLeft: position.screenCoords.clipLeft,
    ghostTop: position.screenCoords.rowTop + 2,
    ghostWidth: position.screenCoords.clipWidth,
    ghostHeight: Math.max(0, position.screenCoords.rowHeight - 4),
    ghostLabel: timeLabel,
    label: position.trackName ? `${position.trackName} · ${timeLabel}` : timeLabel,
    isNewTrack: position.isNewTrack,
    newTrackKind: position.newTrackKind,
    reject: position.isReject,
  };
};

export function useDragCoordinator({
  dataRef,
  scale,
  scaleWidth,
  startLeft,
  rowHeight,
}: UseDragCoordinatorArgs): UseDragCoordinatorResult {
  const indicatorRef = useRef<DropIndicatorHandle | null>(null);
  const editAreaRef = useRef<HTMLElement | null>(null);
  const lastPositionRef = useRef<DropPosition | null>(null);
  const pendingIndicatorRef = useRef<DropIndicatorPosition | null>(null);
  const frameRef = useRef<number | null>(null);

  const flushIndicator = useCallback(() => {
    frameRef.current = null;
    const pending = pendingIndicatorRef.current;
    if (!pending) {
      return;
    }

    indicatorRef.current?.show(pending);
  }, []);

  const end = useCallback(() => {
    if (frameRef.current !== null) {
      window.cancelAnimationFrame(frameRef.current);
      frameRef.current = null;
    }

    pendingIndicatorRef.current = null;
    lastPositionRef.current = null;
    indicatorRef.current?.hide();
  }, []);

  const update = useCallback((params: {
    clientX: number;
    clientY: number;
    sourceKind: TrackKind | null;
    clipDuration?: number;
    clipOffsetX?: number;
  }): DropPosition => {
    const wrapper = editAreaRef.current?.closest<HTMLDivElement>('.timeline-wrapper');
    if (!wrapper) {
      const fallback = lastPositionRef.current ?? buildFallbackPosition(rowHeight, params.sourceKind);
      lastPositionRef.current = fallback;
      return fallback;
    }

    const nextPosition = computeDropPosition({
      clientX: params.clientX,
      clientY: params.clientY,
      wrapper,
      dataRef,
      scale,
      scaleWidth,
      startLeft,
      rowHeight,
      sourceKind: params.sourceKind,
      clipDuration: params.clipDuration,
      clipOffsetX: params.clipOffsetX,
    });

    lastPositionRef.current = nextPosition;
    pendingIndicatorRef.current = toIndicatorPosition(nextPosition);

    if (frameRef.current === null) {
      frameRef.current = window.requestAnimationFrame(flushIndicator);
    }

    return nextPosition;
  }, [dataRef, flushIndicator, rowHeight, scale, scaleWidth, startLeft]);

  const showSecondaryGhosts = useCallback((ghosts: GhostRect[]) => {
    indicatorRef.current?.showSecondaryGhosts(ghosts);
  }, []);

  useEffect(() => {
    return () => {
      end();
    };
  }, [end]);

  const coordinator = useMemo<DragCoordinator>(() => ({
    update,
    showSecondaryGhosts,
    end,
    editAreaRef,
    get lastPosition() {
      return lastPositionRef.current;
    },
  }), [editAreaRef, end, showSecondaryGhosts, update]);

  return {
    coordinator,
    indicatorRef,
    editAreaRef,
  };
}

import type {
  ResolvedTimelineConfig,
  TimelineClip,
  TimelineConfig,
  TrackDefinition,
} from '@/tools/video-editor/types';

export const TIMELINE_CLIP_FIELDS = [
  'id',
  'at',
  'track',
  'clipType',
  'asset',
  'from',
  'to',
  'speed',
  'hold',
  'volume',
  'x',
  'y',
  'width',
  'height',
  'cropTop',
  'cropBottom',
  'cropLeft',
  'cropRight',
  'opacity',
  'text',
  'entrance',
  'exit',
  'continuous',
  'transition',
  'effects',
] as const;

export type TimelineClipField = (typeof TIMELINE_CLIP_FIELDS)[number];

export const TRACK_DEFINITION_FIELDS = [
  'id',
  'kind',
  'label',
  'scale',
  'fit',
  'opacity',
  'blendMode',
] as const;

export type TrackDefinitionField = (typeof TRACK_DEFINITION_FIELDS)[number];

export const serializeClipForDisk = (clip: ResolvedTimelineConfig['clips'][number]): TimelineClip => {
  const serializedClip: Partial<Record<TimelineClipField, TimelineClip[TimelineClipField]>> = {
    id: clip.id,
    at: clip.at,
    track: clip.track,
  };

  if (clip.asset !== undefined) {
    serializedClip.asset = clip.asset;
  }

  for (const field of TIMELINE_CLIP_FIELDS) {
    if (field in serializedClip) {
      continue;
    }

    const value = clip[field];
    if (value !== undefined) {
      serializedClip[field] = value;
    }
  }

  return serializedClip as TimelineClip;
};

export const serializeTrackForDisk = (track: TrackDefinition): TrackDefinition => {
  const serializedTrack: Partial<Record<TrackDefinitionField, TrackDefinition[TrackDefinitionField]>> = {
    id: track.id,
    kind: track.kind,
    label: track.label,
  };

  for (const field of TRACK_DEFINITION_FIELDS) {
    if (field in serializedTrack) {
      continue;
    }

    const value = track[field];
    if (value !== undefined) {
      serializedTrack[field] = value;
    }
  }

  return serializedTrack as TrackDefinition;
};

const ALLOWED_TOP_LEVEL_KEYS = new Set(['output', 'clips', 'tracks', 'customEffects']);

export const validateSerializedConfig = (config: TimelineConfig): void => {
  const topLevelKeys = Object.keys(config);
  const unexpectedKeys = topLevelKeys.filter((key) => !ALLOWED_TOP_LEVEL_KEYS.has(key));
  if (unexpectedKeys.length > 0) {
    throw new Error(`Serialized timeline has unexpected top-level keys: ${unexpectedKeys.join(', ')}`);
  }

  const allowedClipKeys = new Set<string>(TIMELINE_CLIP_FIELDS);
  for (const clip of config.clips) {
    const invalidClipKeys = Object.keys(clip).filter((key) => !allowedClipKeys.has(key));
    if (invalidClipKeys.length > 0) {
      throw new Error(`Serialized clip '${clip.id}' has unexpected keys: ${invalidClipKeys.join(', ')}`);
    }
  }

  const allowedTrackKeys = new Set<string>(TRACK_DEFINITION_FIELDS);
  for (const track of config.tracks ?? []) {
    const invalidTrackKeys = Object.keys(track).filter((key) => !allowedTrackKeys.has(key));
    if (invalidTrackKeys.length > 0) {
      throw new Error(`Serialized track '${track.id}' has unexpected keys: ${invalidTrackKeys.join(', ')}`);
    }
  }
};

export const serializeForDisk = (
  resolved: ResolvedTimelineConfig,
  customEffects?: TimelineConfig['customEffects'],
): TimelineConfig => {
  const serialized: TimelineConfig = {
    output: { ...resolved.output },
    tracks: resolved.tracks.map(serializeTrackForDisk),
    clips: resolved.clips.map(serializeClipForDisk),
  };

  if (customEffects && Object.keys(customEffects).length > 0) {
    serialized.customEffects = customEffects;
  }

  validateSerializedConfig(serialized);
  return serialized;
};

import { useEffect, useRef } from 'react';
import type { MutableRefObject, RefObject } from 'react';
import type { DragCoordinator } from '@/tools/video-editor/hooks/useDragCoordinator';
