import { getClipTimelineDuration } from './config-utils';
import type {
  ResolvedTimelineClip,
  ResolvedTimelineConfig,
  TrackDefinition,
  TrackKind,
} from '@/tools/video-editor/types';

const SPLIT_EPSILON = 0.0001;

export const roundTimelineValue = (value: number, digits = 4): number => {
  const factor = 10 ** digits;
  return Math.round(value * factor) / factor;
};

export const clampValue = (value: number, min: number, max: number): number => {
  return Math.min(Math.max(value, min), max);
};

export const getTrackIndex = (tracks: TrackDefinition[], prefix: 'V' | 'A'): number => {
  return tracks.reduce((maxIndex, track) => {
    const match = track.id.match(new RegExp(`^${prefix}(\\d+)$`));
    return match ? Math.max(maxIndex, Number(match[1])) : maxIndex;
  }, 0);
};

export const getVisualTracks = (config: Pick<ResolvedTimelineConfig, 'tracks'>): TrackDefinition[] => {
  return config.tracks.filter((track) => track.kind === 'visual');
};

export const getAudioTracks = (config: Pick<ResolvedTimelineConfig, 'tracks'>): TrackDefinition[] => {
  return config.tracks.filter((track) => track.kind === 'audio');
};

export const getTrackById = (
  config: Pick<ResolvedTimelineConfig, 'tracks'>,
  trackId: string,
): TrackDefinition | null => {
  return config.tracks.find((track) => track.id === trackId) ?? null;
};

export const addTrack = (
  config: ResolvedTimelineConfig,
  kind: TrackKind,
  index?: number,
): ResolvedTimelineConfig => {
  const prefix = kind === 'visual' ? 'V' : 'A';
  const nextNumber = getTrackIndex(config.tracks, prefix) + 1;
  const nextTrack: TrackDefinition = {
    id: `${prefix}${nextNumber}`,
    kind,
    label: `${prefix}${nextNumber}`,
    scale: 1,
    fit: kind === 'visual' ? 'manual' : 'contain',
    opacity: 1,
    blendMode: 'normal',
  };

  const nextTracks = [...config.tracks];
  if (index === undefined || index < 0 || index > nextTracks.length) {
    nextTracks.push(nextTrack);
  } else {
    nextTracks.splice(index, 0, nextTrack);
  }

  return {
    ...config,
    tracks: nextTracks,
  };
};

export const removeTrack = (
  config: ResolvedTimelineConfig,
  trackId: string,
): ResolvedTimelineConfig => {
  const clips = config.clips.filter((clip) => clip.track !== trackId);
  return {
    ...config,
    tracks: config.tracks.filter((track) => track.id !== trackId),
    clips,
  };
};

export const reorderTracks = (
  config: ResolvedTimelineConfig,
  fromIndex: number,
  toIndex: number,
): ResolvedTimelineConfig => {
  if (
    fromIndex < 0
    || fromIndex >= config.tracks.length
    || toIndex < 0
    || toIndex >= config.tracks.length
    || fromIndex === toIndex
  ) {
    return config;
  }

  const nextTracks = [...config.tracks];
  const [track] = nextTracks.splice(fromIndex, 1);
  nextTracks.splice(toIndex, 0, track);
  return {
    ...config,
    tracks: nextTracks,
  };
};

export const isHoldClip = (clip: ResolvedTimelineClip): boolean => {
  return typeof clip.hold === 'number';
};

export const getClipEndSeconds = (clip: ResolvedTimelineClip): number => {
  return clip.at + getClipTimelineDuration(clip);
};

export const findClipById = (
  config: ResolvedTimelineConfig,
  clipId: string,
): ResolvedTimelineClip | null => {
  return config.clips.find((clip) => clip.id === clipId) ?? null;
};

export const updateClipInConfig = (
  config: ResolvedTimelineConfig,
  clipId: string,
  updater: (clip: ResolvedTimelineClip) => ResolvedTimelineClip,
): ResolvedTimelineConfig => {
  let didUpdate = false;
  const clips = config.clips.map((clip) => {
    if (clip.id !== clipId) {
      return clip;
    }

    didUpdate = true;
    return updater(clip);
  });

  return didUpdate ? { ...config, clips } : config;
};

export const getClipVolume = (clip: ResolvedTimelineClip): number => {
  return clip.volume ?? 1;
};

export const isClipMuted = (clip: ResolvedTimelineClip): boolean => {
  return getClipVolume(clip) <= 0;
};

export const toggleClipMute = (
  config: ResolvedTimelineConfig,
  clipId: string,
): ResolvedTimelineConfig => {
  return updateClipInConfig(config, clipId, (clip) => ({
    ...clip,
    volume: isClipMuted(clip) ? 1 : 0,
  }));
};

export const canSplitClipAtTime = (clip: ResolvedTimelineClip, playheadSeconds: number): boolean => {
  return playheadSeconds > clip.at + SPLIT_EPSILON && playheadSeconds < getClipEndSeconds(clip) - SPLIT_EPSILON;
};

export const createSplitClipId = (
  existingIds: string[],
  originalId: string,
  timestamp = Date.now(),
): string => {
  const used = new Set(existingIds);
  let suffix = 0;

  while (true) {
    const candidate = suffix === 0 ? `${originalId}-${timestamp}` : `${originalId}-${timestamp}-${suffix}`;
    if (!used.has(candidate)) {
      return candidate;
    }

    suffix += 1;
  }
};

export const splitClipAtPlayhead = (
  config: ResolvedTimelineConfig,
  clipId: string,
  playheadSeconds: number,
): { config: ResolvedTimelineConfig; nextSelectedClipId: string | null } => {
  const clipIndex = config.clips.findIndex((clip) => clip.id === clipId);
  if (clipIndex < 0) {
    return { config, nextSelectedClipId: null };
  }

  const clip = config.clips[clipIndex];
  if (!canSplitClipAtTime(clip, playheadSeconds)) {
    return { config, nextSelectedClipId: null };
  }

  const nextSelectedClipId = createSplitClipId(
    config.clips.map((entry) => entry.id),
    clip.id,
  );

  let leftClip: ResolvedTimelineClip;
  let rightClip: ResolvedTimelineClip;

  if (isHoldClip(clip)) {
    const elapsed = roundTimelineValue(playheadSeconds - clip.at);
    const remaining = roundTimelineValue((clip.hold ?? 0) - elapsed);

    leftClip = {
      ...clip,
      hold: elapsed,
    };
    rightClip = {
      ...clip,
      id: nextSelectedClipId,
      at: roundTimelineValue(playheadSeconds),
      hold: remaining,
    };
  } else {
    const speed = clip.speed ?? 1;
    const clipFrom = clip.from ?? 0;
    const splitSource = roundTimelineValue(clipFrom + (playheadSeconds - clip.at) * speed);

    leftClip = {
      ...clip,
      to: splitSource,
    };
    rightClip = {
      ...clip,
      id: nextSelectedClipId,
      at: roundTimelineValue(playheadSeconds),
      from: splitSource,
    };
  }

  const clips = [...config.clips];
  clips.splice(clipIndex, 1, leftClip, rightClip);
  return {
    config: {
      ...config,
      clips,
    },
    nextSelectedClipId,
  };
};

      }

      const kindMoves: Array<{ clipId: string; targetRowId: string }> = [];
      let isBlocked = false;

      for (const group of kindGroups) {
        let targetRowIndex = group.rowIndex;
        let targetRowId: string | null = null;

        while (true) {
          targetRowIndex += direction === 'up' ? -1 : 1;
          if (targetRowIndex < 0 || targetRowIndex >= current.rows.length) {
            isBlocked = true;
            break;
          }

          const targetTrack = trackById.get(current.rows[targetRowIndex]?.id ?? '');
          if (targetTrack?.kind === kind) {
            targetRowId = targetTrack.id;
            break;
          }
        }

        if (isBlocked || !targetRowId) {
          isBlocked = true;
          break;
        }

        for (const clipId of group.clipIds) {
          kindMoves.push({ clipId, targetRowId });
        }
      }

      if (!isBlocked) {
        plannedMoves.push(...kindMoves);
      }
    }

    if (plannedMoves.length === 0) {
      return;
    }

    const transactionId = crypto.randomUUID();

    for (const move of plannedMoves) {
      moveClipToRow(move.clipId, move.targetRowId, undefined, transactionId);
    }

    const primaryMove = selectedClipId
      ? plannedMoves.find((move) => move.clipId === selectedClipId)
      : plannedMoves[0];
    if (primaryMove) {
      setSelectedTrackId(primaryMove.targetRowId);
    }
  }, [dataRef, moveClipToRow, selectedClipId, setSelectedTrackId]);

  const handleAddTrack = useCallback((kind: TrackKind) => {
    if (!resolvedConfig) {
      return;
    }

    const nextResolvedConfig = addTrack(resolvedConfig, kind);
    const nextTrack = nextResolvedConfig.tracks[nextResolvedConfig.tracks.length - 1] ?? null;
    applyResolvedConfigEdit(nextResolvedConfig, { selectedTrackId: nextTrack?.id ?? null });
  }, [applyResolvedConfigEdit, resolvedConfig]);

  const handleTrackPopoverChange = useCallback((trackId: string, patch: Partial<TrackDefinition>) => {
    if (!resolvedConfig) {
      return;
    }

    const nextConfig = {
      ...resolvedConfig,
      tracks: resolvedConfig.tracks.map((track) => (track.id === trackId ? { ...track, ...patch } : track)),
    };
    applyResolvedConfigEdit(nextConfig, { selectedTrackId: trackId });
  }, [applyResolvedConfigEdit, resolvedConfig]);

  const handleMoveTrack = useCallback((activeId: string, overId: string) => {
    if (!resolvedConfig) {
      return;
    }

    const nextTracks = moveTrackWithinKind(resolvedConfig.tracks, activeId, overId);
    if (nextTracks === resolvedConfig.tracks) {
      return;
    }

    applyResolvedConfigEdit({ ...resolvedConfig, tracks: nextTracks }, { selectedTrackId: activeId });
  }, [applyResolvedConfigEdit, resolvedConfig]);

  const handleRemoveTrack = useCallback((trackId: string) => {
    if (!resolvedConfig) {
      return;
    }

    const track = resolvedConfig.tracks.find((entry) => entry.id === trackId);
    if (!track) {
      return;
    }

    const sameKind = resolvedConfig.tracks.filter((entry) => entry.kind === track.kind);
    if (sameKind.length <= 1) {
      return;
    }

    const nextConfig = {
      ...resolvedConfig,
      tracks: resolvedConfig.tracks.filter((entry) => entry.id !== trackId),
      clips: resolvedConfig.clips.filter((clip) => clip.track !== trackId),
    };
    applyResolvedConfigEdit(nextConfig, { selectedTrackId: null, semantic: true });
  }, [applyResolvedConfigEdit, resolvedConfig]);

  const unusedTrackCount = useMemo(() => {
    if (!resolvedConfig) {
      return 0;
    }

    const tracksWithClips = new Set(resolvedConfig.clips.map((clip) => clip.track));
    const defaultTrackIds = new Set(DEFAULT_VIDEO_TRACKS.map((track) => track.id));

    // Count how many tracks would actually be removed (matching handleClearUnusedTracks logic).
    // We always keep at least one track per kind, even if it's empty.
    let keptEmptyVisual = false;
    let keptEmptyAudio = false;
    let removable = 0;

    for (const track of resolvedConfig.tracks) {
      if (defaultTrackIds.has(track.id) || tracksWithClips.has(track.id)) {
        continue;
      }

      if (track.kind === 'visual' && !keptEmptyVisual) {
        const hasVisualWithClips = resolvedConfig.tracks.some((t) => t.kind === 'visual' && tracksWithClips.has(t.id));
        if (!hasVisualWithClips) {
          keptEmptyVisual = true;
          continue;
        }
      }

      if (track.kind === 'audio' && !keptEmptyAudio) {
        const hasAudioWithClips = resolvedConfig.tracks.some((t) => t.kind === 'audio' && tracksWithClips.has(t.id));
        if (!hasAudioWithClips) {
          keptEmptyAudio = true;
          continue;
        }
      }

      removable++;
    }

    return removable;
  }, [resolvedConfig]);

  const handleClearUnusedTracks = useCallback(() => {
    if (!resolvedConfig || unusedTrackCount === 0) {
      return;
    }

    const tracksWithClips = new Set(resolvedConfig.clips.map((clip) => clip.track));
    const defaultTrackIds = new Set(DEFAULT_VIDEO_TRACKS.map((track) => track.id));
    const visualWithClips = resolvedConfig.tracks.filter((track) => track.kind === 'visual' && tracksWithClips.has(track.id));
    const audioWithClips = resolvedConfig.tracks.filter((track) => track.kind === 'audio' && tracksWithClips.has(track.id));

    const nextTracks = resolvedConfig.tracks.filter((track) => {
      if (defaultTrackIds.has(track.id)) {
        return true;
      }

      if (tracksWithClips.has(track.id)) {
        return true;
      }

      if (track.kind === 'visual' && visualWithClips.length === 0) {
        visualWithClips.push(track);
        return true;
      }

      if (track.kind === 'audio' && audioWithClips.length === 0) {
        audioWithClips.push(track);
        return true;
      }

      return false;
    });

    applyResolvedConfigEdit({ ...resolvedConfig, tracks: nextTracks }, { selectedTrackId: null, semantic: true });
  }, [applyResolvedConfigEdit, resolvedConfig, unusedTrackCount]);

  return {
    handleAddTrack,
    handleTrackPopoverChange,
    handleMoveTrack,
    handleRemoveTrack,
    handleClearUnusedTracks,
    unusedTrackCount,
    moveClipToRow,
    createTrackAndMoveClip,
    moveSelectedClipToTrack,
    moveSelectedClipsToTrack,
  };
}

import type { DragEvent as ReactDragEvent, MutableRefObject } from 'react';
import { getDragType } from '@/shared/lib/dnd/dragDrop';
import { rawRowIndexFromY } from '@/tools/video-editor/lib/coordinate-utils';
import type { TimelineData } from '@/tools/video-editor/lib/timeline-data';
import type { TrackKind } from '@/tools/video-editor/types';

interface TimelineDomNodes {
  wrapper: HTMLDivElement;
  editArea: HTMLElement | null;
  grid: HTMLElement | null;
}

interface DropScreenCoords {
  rowTop: number;
  rowLeft: number;
  rowWidth: number;
  rowHeight: number;
  clipLeft: number;
  clipWidth: number;
  ghostCenter: number;
}

export interface DropPosition {
  time: number;
  rowIndex: number;
  trackId: string | undefined;
  trackKind: TrackKind | null;
  trackName: string;
  isNewTrack: boolean;
  isReject: boolean;
  /** When non-null, dropping here will create a new track of this kind. */
  newTrackKind: TrackKind | null;
  screenCoords: DropScreenCoords;
}

export interface ComputeDropPositionParams {
  clientX: number;
  clientY: number;
  wrapper: HTMLDivElement;
  dataRef: MutableRefObject<TimelineData | null>;
  scale: number;
  scaleWidth: number;
  startLeft: number;
  rowHeight: number;
  sourceKind?: TrackKind | null;
  clipDuration?: number;
  clipOffsetX?: number;
}

const timelineDomNodeCache = new WeakMap<HTMLDivElement, Omit<TimelineDomNodes, 'wrapper'>>();
const isValidNode = (wrapper: HTMLDivElement, node: HTMLElement | null): boolean => {
  return node === null || (node.isConnected && wrapper.contains(node));
};

export const getTimelineDomNodes = (wrapper: HTMLDivElement): TimelineDomNodes => {
  const cached = timelineDomNodeCache.get(wrapper);
  if (
    cached
    && isValidNode(wrapper, cached.editArea)
    && isValidNode(wrapper, cached.grid)
  ) {
    return { wrapper, ...cached };
  }

  const editArea = wrapper.querySelector<HTMLElement>('.timeline-canvas-edit-area');
  // In TimelineCanvas the edit area IS the scroll container (grid).
  const grid = editArea;
  const nextNodes = { editArea, grid };
  timelineDomNodeCache.set(wrapper, nextNodes);
  return { wrapper, ...nextNodes };
};

export const computeDropPosition = ({
  clientX,
  clientY,
  wrapper,
  dataRef,
  scale,
  scaleWidth,
  startLeft,
  rowHeight,
  sourceKind = null,
  clipDuration = 5,
  clipOffsetX,
}: ComputeDropPositionParams): DropPosition => {
  const current = dataRef.current;
  const { editArea, grid } = getTimelineDomNodes(wrapper);
  const wrapperRect = wrapper.getBoundingClientRect();
  const editRect = (editArea ?? wrapper).getBoundingClientRect();
  const scrollLeft = grid?.scrollLeft ?? 0;
  const scrollTop = grid?.scrollTop ?? 0;
  const pixelsPerSecond = scaleWidth / scale;
  const effectiveOffsetX = clipOffsetX ?? (clipDuration * pixelsPerSecond) / 2;
  const leftInGrid = clientX - editRect.left + scrollLeft - effectiveOffsetX;
  const time = Math.max(0, (leftInGrid - startLeft) / pixelsPerSecond);

  const rowCount = current?.rows.length ?? 0;
  const rawRowIndex = rawRowIndexFromY(clientY, editRect.top, scrollTop, rowHeight);
  const isNewTrack = rowCount === 0 || rawRowIndex >= rowCount;
  const rowIndex = rowCount === 0
    ? 0
    : isNewTrack
      ? rowCount
      : Math.min(Math.max(rawRowIndex, 0), rowCount - 1);
  const visualRowIndex = rowCount > 0 ? Math.min(rowIndex, rowCount - 1) : -1;
  const targetRow = visualRowIndex >= 0 ? current?.rows[visualRowIndex] : undefined;
  const targetTrack = visualRowIndex >= 0 ? current?.tracks[visualRowIndex] : undefined;
  const rowTop = visualRowIndex >= 0
    ? editRect.top + visualRowIndex * rowHeight - scrollTop
    : editRect.top;
  const clipLeft = editRect.left + startLeft + time * pixelsPerSecond - scrollLeft;
  const clipWidth = Math.max(0, Math.min(clipDuration * pixelsPerSecond, editRect.right - clipLeft));
  const ghostCenter = clipLeft + clipWidth / 2;
  const kindMismatch = !isNewTrack && sourceKind !== null && targetTrack?.kind !== undefined && sourceKind !== targetTrack.kind;

  // When kind doesn't match, silently resolve to the first compatible track.
  // Only create a new track if no compatible one exists at all.
  let resolvedTrackId = targetRow?.id;
  let resolvedTrackName = targetTrack?.label ?? targetTrack?.id ?? '';
  let resolvedTrackKind = targetTrack?.kind ?? null;
  let needsNewTrack = isNewTrack;
  let newTrackKind: TrackKind | null = isNewTrack ? sourceKind : null;

  if (kindMismatch && current && sourceKind) {
    // Find the nearest compatible track to the hovered row
    const compatibleTracks = current.tracks
      .map((t, i) => ({ track: t, index: i }))
      .filter(({ track }) => track.kind === sourceKind);
    const nearest = compatibleTracks.length > 0
      ? compatibleTracks.reduce((best, candidate) =>
          Math.abs(candidate.index - rowIndex) < Math.abs(best.index - rowIndex) ? candidate : best)
      : null;
    if (nearest) {
      const compatible = nearest.track;
      resolvedTrackId = compatible.id;
      resolvedTrackName = compatible.label ?? compatible.id;
      resolvedTrackKind = compatible.kind;
      const compatibleIndex = nearest.index;
      const compatibleRowTop = compatibleIndex >= 0
        ? editRect.top + compatibleIndex * rowHeight - scrollTop
        : rowTop;
      return {
        time,
        rowIndex: compatibleIndex,
        trackId: resolvedTrackId,
        trackKind: resolvedTrackKind,
        trackName: resolvedTrackName,
        isNewTrack: false,
        isReject: false,
        newTrackKind: null,
        screenCoords: {
          rowTop: compatibleRowTop,
          rowLeft: wrapperRect.left,
          rowWidth: wrapperRect.width,
          rowHeight,
          clipLeft,
          clipWidth,
          ghostCenter,
        },
      };
    }
    // No compatible track exists — will create one silently on drop
    needsNewTrack = true;
    newTrackKind = sourceKind;
    resolvedTrackId = undefined;
    resolvedTrackKind = sourceKind;
    resolvedTrackName = '';
  }

  return {
    time,
    rowIndex,
    trackId: needsNewTrack ? undefined : resolvedTrackId,
    trackKind: needsNewTrack ? sourceKind : resolvedTrackKind,
    trackName: resolvedTrackName,
    isNewTrack: needsNewTrack,
    isReject: false,
    newTrackKind,
    screenCoords: {
      rowTop,
      rowLeft: wrapperRect.left,
      rowWidth: wrapperRect.width,
      rowHeight,
      clipLeft,
      clipWidth,
      ghostCenter,
    },
  };
};

export const inferDragKind = (event: ReactDragEvent<HTMLDivElement>): TrackKind | null => {
  const types = Array.from(event.dataTransfer.types);
  if (types.includes('asset-kind:audio')) return 'audio';
  if (types.includes('asset-kind:visual')) return 'visual';
  if (types.includes('asset-key')) return null;
  if (getDragType(event) === 'generation') return 'visual';
  if (event.dataTransfer.items.length > 0) {
    for (const item of Array.from(event.dataTransfer.items)) {
      if (item.type.startsWith('audio/')) {
        return 'audio';
      }
    }
    return 'visual';
  }
  return null;
};

import type { TrackKind } from '@/tools/video-editor/types';
import type { ClipMeta, ClipOrderMap, TimelineData } from '@/tools/video-editor/lib/timeline-data';
import type { TimelineRow } from '@/tools/video-editor/types/timeline-canvas';
import { moveClipBetweenTracks } from '@/tools/video-editor/lib/coordinate-utils';
import { resolveGroupOverlaps, type GroupMovedClip } from '@/tools/video-editor/lib/resolve-overlaps';

// ── Types ────────────────────────────────────────────────────────────

export interface ClipOffset {
  clipId: string;
  rowId: string;
  /** Time delta from anchor clip's initial start. */
  deltaTime: number;
  initialStart: number;
  initialEnd: number;
}

export interface PlannedMove {
  clipId: string;
  sourceRowId: string;
  targetRowId: string;
  newStart: number;
}

export interface MultiDragResult {
  canMove: boolean;
  moves: PlannedMove[];
}

/** Lightweight rect for rendering secondary ghost indicators. */
export interface GhostRect {
  left: number;
  top: number;
  width: number;
  height: number;
}

// ── Planning ─────────────────────────────────────────────────────────

/**
 * Given a set of dragged clips, an anchor target row, and a time delta,
 * compute where every clip should land. Returns `canMove: false` if any
 * clip would go out of bounds or land on an incompatible track kind.
 *
 * Works for both same-track and cross-track drags — the caller just
 * provides the anchor's resolved target row and time.
 */
export function planMultiDragMoves(
  data: TimelineData,
  clipOffsets: readonly ClipOffset[],
  anchorClipId: string,
  anchorTargetRowId: string,
  anchorSourceRowId: string,
  timeDelta: number,
): MultiDragResult {
  const rowIds = data.rows.map((r) => r.id);
  const trackById = new Map(data.tracks.map((t) => [t.id, t]));
  const anchorSourceIndex = rowIds.indexOf(anchorSourceRowId);
  const anchorTargetIndex = rowIds.indexOf(anchorTargetRowId);
  const trackDelta = anchorTargetIndex - anchorSourceIndex;

  if (trackDelta === 0 && timeDelta === 0) {
    return { canMove: false, moves: [] };
  }

  const moves: PlannedMove[] = [];

  for (const offset of clipOffsets) {
    const sourceIndex = rowIds.indexOf(offset.rowId);
    const targetIndex = sourceIndex + trackDelta;

    if (targetIndex < 0 || targetIndex >= rowIds.length) {
      return { canMove: false, moves: [] };
    }

    const targetRowId = rowIds[targetIndex];
    const sourceTrack = trackById.get(offset.rowId);
    const targetTrack = trackById.get(targetRowId);

    if (!sourceTrack || !targetTrack || sourceTrack.kind !== targetTrack.kind) {
      return { canMove: false, moves: [] };
    }

    moves.push({
      clipId: offset.clipId,
      sourceRowId: offset.rowId,
      targetRowId,
      newStart: offset.initialStart + timeDelta,
    });
  }

  return { canMove: true, moves };
}

// ── Applying ─────────────────────────────────────────────────────────

/**
 * Apply a set of planned moves to the timeline rows, resolve overlaps,
 * and update clip ordering. Returns the new rows, meta updates, and
 * clip order — ready to pass to `applyTimelineEdit`.
 */
export function applyMultiDragMoves(
  data: TimelineData,
  moves: PlannedMove[],
): {
  nextRows: TimelineRow[];
  metaUpdates: Record<string, Partial<ClipMeta>>;
  nextClipOrder: ClipOrderMap;
} {
  const movedClipIds = new Set(moves.map((m) => m.clipId));

  // Remove all moved clips from their source rows
  let nextRows = data.rows.map((row) => ({
    ...row,
    actions: row.actions.filter((a) => !movedClipIds.has(a.id)),
  }));

  // Build a map of actions to add per target row (single pass)
  const actionsToAdd = new Map<string, typeof data.rows[0]['actions']>();
  const metaUpdates: Record<string, Partial<ClipMeta>> = {};

  for (const move of moves) {
    const originalRow = data.rows.find((r) => r.id === move.sourceRowId);
    const action = originalRow?.actions.find((a) => a.id === move.clipId);
    if (!action) continue;

    const duration = action.end - action.start;
    const newStart = Math.max(0, move.newStart);
    const movedAction = { ...action, start: newStart, end: newStart + duration };

    const existing = actionsToAdd.get(move.targetRowId) ?? [];
    existing.push(movedAction);
    actionsToAdd.set(move.targetRowId, existing);

    if (move.sourceRowId !== move.targetRowId) {
      metaUpdates[move.clipId] = { track: move.targetRowId };
    }
  }

  // Add moved actions to target rows (single pass over rows)
  nextRows = nextRows.map((row) => {
    const additions = actionsToAdd.get(row.id);
    return additions ? { ...row, actions: [...row.actions, ...additions] } : row;
  });

  // Resolve overlaps per target row
  const targetRowIds = new Set(moves.map((m) => m.targetRowId));
  for (const targetRowId of targetRowIds) {
    const rowMoves = moves.filter((m) => m.targetRowId === targetRowId);
    const groupMoved: GroupMovedClip[] = rowMoves.map((m) => {
      const originalRow = data.rows.find((r) => r.id === m.sourceRowId);
      const action = originalRow?.actions.find((a) => a.id === m.clipId);
      const duration = action ? action.end - action.start : 0;
      const newStart = Math.max(0, m.newStart);
      return { rowId: targetRowId, clipId: m.clipId, newStart, newEnd: newStart + duration };
    });
    nextRows = resolveGroupOverlaps(nextRows, groupMoved, data.meta);
  }

  // Update clip order for cross-track moves
  let nextClipOrder = data.clipOrder;
  for (const move of moves) {
    if (move.sourceRowId !== move.targetRowId) {
      nextClipOrder = moveClipBetweenTracks(nextClipOrder, move.clipId, move.sourceRowId, move.targetRowId);
    }
  }

  return { nextRows, metaUpdates, nextClipOrder };
}

// ── Ghost indicators ─────────────────────────────────────────────────

/**
 * Compute ghost rectangles for secondary (non-anchor) clips during a
 * multi-drag, using the anchor's screen position as the reference point.
 */
export function computeSecondaryGhosts(
  clipOffsets: readonly ClipOffset[],
  anchorClipId: string,
  anchorSourceRowId: string,
  anchorTargetRowId: string,
  anchorGhostLeft: number,
  anchorRowTop: number,
  rowHeight: number,
  pixelsPerSecond: number,
  rowIds: readonly string[],
): GhostRect[] {
  const anchorSourceIndex = rowIds.indexOf(anchorSourceRowId);
  const anchorTargetIndex = rowIds.indexOf(anchorTargetRowId);
  const trackDelta = anchorTargetIndex - anchorSourceIndex;

  const ghosts: GhostRect[] = [];

  for (const offset of clipOffsets) {
    if (offset.clipId === anchorClipId) continue;

    const sourceIndex = rowIds.indexOf(offset.rowId);
    const targetIndex = sourceIndex + trackDelta;
    if (targetIndex < 0 || targetIndex >= rowIds.length) continue;

    const rowDelta = targetIndex - anchorTargetIndex;
    const clipDuration = offset.initialEnd - offset.initialStart;

    ghosts.push({
      left: anchorGhostLeft + (offset.deltaTime * pixelsPerSecond),
      top: anchorRowTop + (rowDelta * rowHeight) + 2,
      width: clipDuration * pixelsPerSecond,
      height: Math.max(0, rowHeight - 4),
    });
  }

  return ghosts;
}

import { useCallback, useRef } from 'react';
import { buildRowTrackPatches } from '@/tools/video-editor/lib/coordinate-utils';
import { getSourceTime, type ClipMeta, type TimelineData } from '@/tools/video-editor/lib/timeline-data';
import { resolveOverlaps } from '@/tools/video-editor/lib/resolve-overlaps';
import type { UseTimelineDataResult } from '@/tools/video-editor/hooks/useTimelineData';
import type { TimelineAction, TimelineRow } from '@/tools/video-editor/types/timeline-canvas';

export interface UseClipResizeArgs {
  dataRef: React.MutableRefObject<TimelineData | null>;
  applyTimelineEdit: UseTimelineDataResult['applyTimelineEdit'];
}

export interface UseClipResizeResult {
  onActionResizeStart: ({ action }: { action: TimelineAction }) => void;
  onActionResizeEnd: ({ action, row }: { action: TimelineAction; row: TimelineRow; dir: string }) => void;
}

export function useClipResize({
  dataRef,
  applyTimelineEdit,
}: UseClipResizeArgs): UseClipResizeResult {
  const resizeStartRef = useRef<Record<string, { start: number; from: number }>>({});
  const resizeTransactionIdRef = useRef<Record<string, string>>({});

  const onActionResizeStart = useCallback(({ action }: { action: TimelineAction }) => {
    if (action.id.startsWith('uploading-')) return;
    const clipMeta = dataRef.current?.meta[action.id];
    if (!clipMeta || typeof clipMeta.hold === 'number') {
      return;
    }

    resizeStartRef.current[action.id] = {
      start: action.start,
      from: clipMeta.from ?? 0,
    };
    resizeTransactionIdRef.current[action.id] = crypto.randomUUID();
  }, [dataRef]);

  const onActionResizeEnd = useCallback(({ action, row }: { action: TimelineAction; row: TimelineRow; dir: string }) => {
    if (action.id.startsWith('uploading-')) return;
    const current = dataRef.current;
    const clipMeta = current?.meta[action.id];
    if (!current || !clipMeta) {
      return;
    }

    const metaUpdates: Record<string, Partial<ClipMeta>> = {
      ...buildRowTrackPatches(current.rows),
      [action.id]: {
        track: row.id,
      },
    };

    if (typeof clipMeta.hold !== 'number') {
      const origin = resizeStartRef.current[action.id];
      if (origin && action.start !== origin.start) {
        metaUpdates[action.id] = {
          ...metaUpdates[action.id],
          from: Math.max(0, origin.from + (action.start - origin.start) * (clipMeta.speed ?? 1)),
        };
      }

      metaUpdates[action.id] = {
        ...metaUpdates[action.id],
        to: getSourceTime(
          {
            from: clipMeta.from ?? 0,
            start: action.start,
            speed: clipMeta.speed ?? 1,
          },
          action.end,
        ),
      };
    }

    let nextRows = current.rows.map((entry) => {
      if (entry.id !== row.id) {
        return entry;
      }

      return {
        ...entry,
        actions: entry.actions.map((candidate) => {
          return candidate.id === action.id
            ? { ...candidate, start: action.start, end: action.end }
            : candidate;
        }),
      };
    });

    // Trim the resized clip if it overlaps existing siblings
    const { rows: resolvedRows, metaPatches: overlapPatches } = resolveOverlaps(
      nextRows, row.id, action.id, current.meta,
    );

    applyTimelineEdit(
      resolvedRows,
      { ...metaUpdates, ...overlapPatches },
      undefined,
      undefined,
      { transactionId: resizeTransactionIdRef.current[action.id] },
    );
    delete resizeStartRef.current[action.id];
    delete resizeTransactionIdRef.current[action.id];
  }, [applyTimelineEdit, dataRef]);

  return {
    onActionResizeStart,
    onActionResizeEnd,
  };
}

import { useCallback, useEffect, useRef } from 'react';
import { getGenerationDropData, getDragType } from '@/shared/lib/dnd/dragDrop';
import { inferDragKind } from '@/tools/video-editor/lib/drop-position';
import type { DragCoordinator } from '@/tools/video-editor/hooks/useDragCoordinator';
import type { UseAssetManagementResult } from '@/tools/video-editor/hooks/useAssetManagement';
import type { UseTimelineDataResult } from '@/tools/video-editor/hooks/useTimelineData';
import {
  createEffectLayerClipMeta,
  getNextClipId,
  type ClipMeta,
  type TimelineData,
} from '@/tools/video-editor/lib/timeline-data';
import type { TimelineAction } from '@/tools/video-editor/types/timeline-canvas';
import type { TrackKind } from '@/tools/video-editor/types';
import { getCompatibleTrackId, updateClipOrder } from '@/tools/video-editor/lib/coordinate-utils';
import { getTrackIndex } from '@/tools/video-editor/lib/editor-utils';
import { createAutoScroller } from '@/tools/video-editor/lib/auto-scroll';
import { resolveOverlaps } from '@/tools/video-editor/lib/resolve-overlaps';

export interface UseExternalDropArgs {
  dataRef: React.MutableRefObject<TimelineData | null>;
  scale: number;
  scaleWidth: number;
  selectedTrackId: string | null;
  applyTimelineEdit: UseTimelineDataResult['applyTimelineEdit'];
  patchRegistry: UseTimelineDataResult['patchRegistry'];
  registerAsset: UseTimelineDataResult['registerAsset'];
  uploadAsset: UseTimelineDataResult['uploadAsset'];
  invalidateAssetRegistry: UseTimelineDataResult['invalidateAssetRegistry'];
  resolveAssetUrl: (file: string) => Promise<string>;
  coordinator: DragCoordinator;
  registerGenerationAsset: UseAssetManagementResult['registerGenerationAsset'];
  uploadImageGeneration: UseAssetManagementResult['uploadImageGeneration'];
  handleAssetDrop: UseAssetManagementResult['handleAssetDrop'];
  handleAddTextAt?: (trackId: string, time: number) => void;
}

export interface UseExternalDropResult {
  onTimelineDragOver: (event: React.DragEvent<HTMLDivElement>) => void;
  onTimelineDragLeave: (event: React.DragEvent<HTMLDivElement>) => void;
  onTimelineDrop: (event: React.DragEvent<HTMLDivElement>) => void;
}

export function useExternalDrop({
  dataRef,
  selectedTrackId,
  applyTimelineEdit,
  patchRegistry,
  uploadAsset,
  invalidateAssetRegistry,
  resolveAssetUrl,
  coordinator,
  registerGenerationAsset,
  uploadImageGeneration,
  handleAssetDrop,
  handleAddTextAt,
}: UseExternalDropArgs): UseExternalDropResult {
  const externalDragFrameRef = useRef<number | null>(null);
  const autoScrollerRef = useRef<ReturnType<typeof createAutoScroller> | null>(null);
  const latestExternalDragRef = useRef<{
    clientX: number;
    clientY: number;
    sourceKind: TrackKind | null;
  } | null>(null);
  const latestExternalPositionRef = useRef<ReturnType<DragCoordinator['update']> | null>(null);

  const clearExternalDragState = useCallback(() => {
    if (externalDragFrameRef.current !== null) {
      window.cancelAnimationFrame(externalDragFrameRef.current);
      externalDragFrameRef.current = null;
    }
    autoScrollerRef.current?.stop();
    autoScrollerRef.current = null;
    latestExternalDragRef.current = null;
    latestExternalPositionRef.current = null;
    coordinator.end();
  }, [coordinator]);

  useEffect(() => {
    return () => {
      clearExternalDragState();
    };
  }, [clearExternalDragState]);

  const onTimelineDragOver = useCallback((event: React.DragEvent<HTMLDivElement>) => {
    const dragType = getDragType(event);
    const types = Array.from(event.dataTransfer.types);
    if (!types.includes('asset-key') && !types.includes('text-tool') && !types.includes('effect-layer') && dragType !== 'file' && dragType !== 'generation') {
      return;
    }
    event.preventDefault();
    event.stopPropagation();
    event.currentTarget.dataset.dragOver = 'true';
    latestExternalDragRef.current = {
      clientX: event.clientX,
      clientY: event.clientY,
      sourceKind: inferDragKind(event),
    };
    if (!autoScrollerRef.current && coordinator.editAreaRef.current) {
      autoScrollerRef.current = createAutoScroller(coordinator.editAreaRef.current, (clientX, clientY) => {
        const currentDrag = latestExternalDragRef.current;
        if (!currentDrag) {
          return;
        }

        latestExternalPositionRef.current = coordinator.update({
          clientX,
          clientY,
          sourceKind: currentDrag.sourceKind,
        });
      });
    }
    autoScrollerRef.current?.update(event.clientX, event.clientY);

    if (externalDragFrameRef.current !== null) {
      return;
    }

    externalDragFrameRef.current = window.requestAnimationFrame(() => {
      externalDragFrameRef.current = null;
      const currentDrag = latestExternalDragRef.current;
      if (!currentDrag) {
        return;
      }

      latestExternalPositionRef.current = coordinator.update({
        clientX: currentDrag.clientX,
        clientY: currentDrag.clientY,
        sourceKind: currentDrag.sourceKind,
      });
    });
  }, [coordinator]);

  const onTimelineDragLeave = useCallback((event: React.DragEvent<HTMLDivElement>) => {
    delete event.currentTarget.dataset.dragOver;
    clearExternalDragState();
  }, [clearExternalDragState]);

  const onTimelineDrop = useCallback(async (event: React.DragEvent<HTMLDivElement>) => {
    event.preventDefault();
    delete event.currentTarget.dataset.dragOver;
    autoScrollerRef.current?.stop();
    autoScrollerRef.current = null;
    if (externalDragFrameRef.current !== null) {
      window.cancelAnimationFrame(externalDragFrameRef.current);
      externalDragFrameRef.current = null;
    }

    if (latestExternalDragRef.current) {
      latestExternalPositionRef.current = coordinator.update({
        clientX: latestExternalDragRef.current.clientX,
        clientY: latestExternalDragRef.current.clientY,
        sourceKind: latestExternalDragRef.current.sourceKind,
      });
    }

    const dropPosition = coordinator.lastPosition
      ?? latestExternalPositionRef.current
      ?? coordinator.update({
        clientX: event.clientX,
        clientY: event.clientY,
        sourceKind: inferDragKind(event),
      });

    latestExternalDragRef.current = null;
    latestExternalPositionRef.current = null;
    coordinator.end();

    // Handle text-tool drop
    const isTextTool = event.dataTransfer.types.includes('text-tool');
    if (isTextTool && handleAddTextAt && dataRef.current) {
      let targetTrackId = dropPosition.isNewTrack ? undefined : dropPosition.trackId;
      if (!targetTrackId) {
        // Create a new visual track immutably
        const current = dataRef.current;
        const nextNumber = getTrackIndex(current.tracks, 'V') + 1;
        targetTrackId = `V${nextNumber}`;
        dataRef.current = {
          ...current,
          tracks: [...current.tracks, { id: targetTrackId, kind: 'visual' as const, label: `V${nextNumber}` }],
          rows: [...current.rows, { id: targetTrackId, actions: [] }],
