          hold: resolvedAction ? Math.max(0.05, resolvedAction.end - resolvedAction.start) : clipMeta.hold,
        },
      }, undefined, nextClipOrder);
      return;
    }

    const files = Array.from(event.dataTransfer.files);
    if (files.length > 0 && dataRef.current) {
